#include <iostream>#include <string>using namespace std;// Dadosstring personagens[3] = {"Tommy", "Jerryzinho", "Spike"};int idades[3] = {5, 2, 7};// Funçõesvoid mostrarPersonagens() {cout << "=== PERSONAGENS DISPONIVEIS ===" << endl;for (int i = 0; i < 3; i++) {cout << i << " - " << personagens[i] << " (" << idades[i] << " anos)" << endl;}}void mostrarMenu() {cout << endl;cout << "1 - Correr" << endl;cout << "2 - Comer" << endl;cout << "3 - Dormir" << endl;cout << "0 - Sair" << endl;}void executarAcao(int escolha, string personagem) {if (escolha == 1) {cout << personagem << " correu muito rapido! 🏃" << endl;}else if (escolha == 2) {cout << personagem << " comeu comida 🧀" << endl;}else if (escolha == 3) {cout << personagem << " foi dormir 😴" << endl;}else if (escolha == 0) {cout << "Saindo do jogo... 👋" << endl;}else {cout << "Opcao invalida 😅" << endl;}}int main() {int escolhaPersonagem;int escolhaAcao;bool continuar = true;    cout << "=== JOGO FINAL 🐱🐭 ===" << endl;    mostrarPersonagens();    cout << "Escolhe um personagem: ";    cin >> escolhaPersonagem;    if (escolhaPersonagem < 0 || escolhaPersonagem > 2) {        cout << "Personagem invalido!" << endl;        return 0;    }    string personagemSelecionado = personagens[escolhaPersonagem];    while (continuar) {        mostrarMenu();        cout << "Opcao: ";        cin >> escolhaAcao;        executarAcao(escolhaAcao, personagemSelecionado);        if (escolhaAcao == 0) {            continuar = false;        }    }    return 0;}